body {
  font-family: "Figtree", sans-serif;
  background: transparent;
  color: #05042E;
  font-size: 13px;
}

.wrap {
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.section-title {
  font-size: 11px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

