  }
  if (type === 'customer') return { icon: 'user-plus', bg: 'rgba(70,155,192,0.12)', color: '#469BC0' };
  if (type === 'asset') return { icon: 'box', bg: 'rgba(5,4,46,0.06)', color: '#05042E' };
  return { icon: 'circle', bg: 'rgba(5,4,46,0.04)', color: '#888780' };
}

function getTitle(activity) {
  if (activity.activity_type === 'collection') {
    return `Collection ${activity.status?.toLowerCase() || 'updated'} — ${activity.record_id || 'Job'}`;
  }
  if (activity.activity_type === 'customer') {
    return `New customer created — ${activity.title_detail}`;
  }
  if (activity.activity_type === 'asset') {
    return `Asset ${activity.status?.toLowerCase() || 'updated'} — ${activity.title_detail || ('#' + activity.record_id)}`;
  }
  return activity.title_detail || 'Activity';
}

function timeAgo(dateStr) {
  if (!dateStr) return '';
  const date = new Date(dateStr);
  const now = new Date();
  const diffMs = now - date;
  const diffMins = Math.floor(diffMs / 60000);
  const diffHours = Math.floor(diffMins / 60);
  const diffDays = Math.floor(diffHours / 24);
  if (diffMins < 1) return 'just now';
  if (diffMins < 60) return `${diffMins}m ago`;
  if (diffHours < 24) return `${diffHours}h ago`;
  if (diffDays === 1) return 'yesterday';
  return `${diffDays}d ago`;
}

function App() {
  const [model, setModel] = React.useState(appsmith.model);

  React.useEffect(() => {
    appsmith.onModelChange((newModel) => {
      setModel({ ...newModel });
    });
  }, []);

  let activities = model.activities;
  if (typeof activities === 'string') {
    try { activities = JSON.parse(activities); } catch (e) { activities = []; }
  }
  activities = activities || [];

  if (activities.length === 0) {
    return (
      <div style={{
        textAlign: 'center', padding: '24px 0',
        color: '#888780', fontSize: '13px',
        fontFamily: "'Figtree', sans-serif"
      }}>
        No recent activity
      </div>
    );
  }

  return (
    <div style={{ fontFamily: "'Figtree', sans-serif", display: 'flex', flexDirection: 'column', gap: '6px' }}>
      {activities.map((activity, i) => {
        const { icon, bg, color } = getIcon(activity.activity_type, activity.status);
        return (
          <div key={i} style={{
            background: '#fff',
            border: '0.5px solid rgba(0,0,0,0.08)',
            borderRadius: '8px',
            padding: '10px 12px',
            display: 'flex',
            alignItems: 'center',
            gap: '10px'
          }}>
            <div style={{
              width: '32px', height: '32px', borderRadius: '50%',
              background: bg, display: 'flex', alignItems: 'center',
              justifyContent: 'center', flexShrink: 0
            }}>
              <i className={`ti ti-${icon}`} style={{ fontSize: '15px', color: color }}></i>
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{
                fontSize: '12px', fontWeight: 600, color: '#05042E',
                whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis'
              }}>
                {getTitle(activity)}
              </div>
              <div style={{ fontSize: '11px', color: '#888780', marginTop: '1px' }}>
                {activity.created_by || 'System'}
              </div>
            </div>
            <div style={{
              fontSize: '10px', color: '#888780',
              flexShrink: 0, fontWeight: 600,
              textTransform: 'uppercase', letterSpacing: '0.03em'
            }}>
              {timeAgo(activity.created_at)}
            </div>
          </div>
        );
      })}
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
